@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

.app {
  width: 100%;
  font-family: "Figtree", sans-serif;
  background: #fff;
  border-radius: 12px;
  padding: 20px 24px;
  border: 0.5px solid rgba(0, 0, 0, 0.12);
}

.header-row {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 16px;
  flex-wrap: wrap;
}

.identity {
  display: flex;
  align-items: flex-start;
  gap: 14px;
}

.icon-box {
  width: 44px;
  height: 44px;
  border-radius: 8px;
  background: rgba(70, 155, 192, 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  font-size: 22px;
}

.label-sm {
  font-size: 11px;
  color: #888780;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin: 0 0 2px;
}

.title-lg {
  font-size: 22px;
  font-weight: 700;
  margin: 0;
  color: #05042E;
  letter-spacing: -0.01em;
}

.serial-sm {
  font-size: 12px;
  color: #888780;
  margin: 4px 0 0;
}

.text-right {
  text-align: right;
}

.value-md {
  font-size: 14px;
  font-weight: 700;
  margin: 0;
  color: #05042E;
}

.dial-row {
  margin-top: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.dial-label {
  font-size: 11px;
  color: #888780;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.dial-value {
  font-size: 12px;
  color: #469BC0;
  font-weight: 600;
}

.divider {
  border-top: 0.5px solid rgba(0, 0, 0, 0.08);
  margin: 16px 0;
}

.tile-grid-4 {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
}

.tile {
  border-radius: 8px;
  padding: 12px 14px;
}

.tile-label {
  font-size: 10px;
  font-weight: 700;
  margin: 0 0 6px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.tile-value-lg {
  font-size: 18px;
  font-weight: 700;
}

.tile-value-md {
  font-size: 14px;
  font-weight: 600;
}

.tile-sub {
  font-size: 11px;
  margin: 6px 0 0;
  opacity: 0.8;
}

.status-badge {
  display: inline-block;
  font-size: 12px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 6px;
}

.grade-tile {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.grade-circle {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: #ffffff;
  border: 3px solid #4338ca;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.grade-text {
  font-size: 22px;
  font-weight: 700;
  line-height: 1;
}

.grade-label {
  font-size: 10px;
  font-weight: 700;
  margin: 0 0 4px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.grade-sub {
  font-size: 11px;
  margin: 0;
  opacity: 0.85;
}

.status-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  align-items: center;
}

.status-label {
  font-size: 11px;
  color: #888780;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.status-select-inline {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  padding: 7px 10px;
  border-radius: 6px;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  background: #fff;
  font-family: "Figtree", sans-serif;
  outline: none;
}

.status-select-inline:focus {
  border-color: #469BC0;
}

