      <div className="tile-grid-4">
        <div className="tile" style={{ background: 'rgba(5,4,46,0.04)' }}>
          <p className="tile-label" style={{ color: '#888780' }}>Status</p>
          <span className="status-badge" style={getCategoryStyle(currentStatus?.category)}>
            {currentStatus?.status_name || "—"}
          </span>
          {erasureRequired && (
            <p className="tile-sub" style={{ color: '#888780' }}>Erasure required before sale/disposal</p>
          )}
        </div>

        <div className="tile" style={dbStyle}>
          <p className="tile-label" style={{ color: dbStyle.color }}>Data bearing</p>
          <span className="tile-value-lg" style={{ color: dbStyle.color }}>{dbValue}</span>
          {dataBearing && erasureDone && <p className="tile-sub" style={{ color: dbStyle.color }}>Erasure confirmed</p>}
          {dataBearing && !erasureDone && <p className="tile-sub" style={{ color: dbStyle.color }}>Awaiting erasure</p>}
        </div>

        <div className="tile" style={erasureStyle}>
          <p className="tile-label" style={{ color: erasureStyle.color }}>Erasure state</p>
          <div className="tile-value-md" style={{ color: erasureStyle.color }}>{erasure}</div>
          <p className="tile-sub" style={{ color: erasureStyle.color }}>via Blancco</p>
        </div>

        <div className="tile grade-tile" style={gradeTileStyle}>
          <div>
            <p className="grade-label" style={{ color: gradeColor }}>Grade</p>
            <p className="grade-sub" style={{ color: gradeColor }}>{gradeSub}</p>
          </div>
          <div className="grade-circle" style={{ border: '3px solid ' + gradeColor }}>
            <span className="grade-text" style={{ opacity: gradeOpacity, color: gradeColor }}>{gradeText}</span>
          </div>
        </div>
      </div>

      <div className="divider"></div>

      <div className="status-row">
        <span className="status-label">Update status</span>
        <select
          className="status-select-inline"
          value={currentStatusId || ""}
          onChange={handleStatusChange}
        >
          {statusTypes.map((s) => {
            const blocked = isLocked && s.status_id !== STRIPPED_STATUS_ID;
            return (
              <option key={s.status_id} value={s.status_id} disabled={blocked}>
                {s.status_name}{blocked ? " (locked)" : ""}
              </option>
            );
          })}
        </select>
        {isLocked && (
          <span style={{ fontSize: '11px', color: '#b91c1c', fontWeight: 600 }}>
            🔒 Clear lock in Grading tab to enable all statuses
          </span>
        )}
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
